1	import { useEffect, useRef } from "react";
2	import { useQuery, useMutation, useQueryClient, type QueryClient } from "@tanstack/react-query";
3	import * as api from "@/lib/api/client";
4	import type {
5	  ProbabilityEditPayload,
6	  EventTradePayload,
7	  CommentPayload,
8	  Session,
9	  MarketDetailResponse,
10	  MarketPriceMessage,
11	  MarketStatus,
12	  MarketListFilterInput,
13	} from "@/lib/api/types";
14	
15	export const queryKeys = {
16	  markets: (filters?: MarketListFilterInput) => ["markets", api.normalizeMarketListFilters(filters)] as const,
17	  market: (id: string) => ["markets", id] as const,
18	  marketEvents: (id: string) => ["markets", id, "events"] as const,
19	  marketComments: (id: string) => ["markets", id, "comments"] as const,
20	  engineStats: (id: string) => ["markets", id, "engine-stats"] as const,
21	  marketAnalytics: (id: string, interval?: string) => ["markets", id, "analytics", interval ?? "1h"] as const,
22	  accountRisk: (id: string) => ["accounts", id, "risk"] as const,
23	  accountExposure: (id: string) => ["accounts", id, "exposure"] as const,
24	  health: () => ["health"] as const,
25	  serviceIndex: () => ["service-index"] as const,
26	};
27	
28	const INITIAL_RECONNECT_DELAY_MS = 500;
29	const MAX_RECONNECT_DELAY_MS = 5000;
30	
31	function invalidateMarketCollectionQueries(qc: QueryClient) {
32	  return qc.invalidateQueries({
33	    predicate: ({ queryKey }) => Array.isArray(queryKey)
34	      && queryKey[0] === "markets"
35	      && typeof queryKey[1] === "object"
36	      && queryKey[1] !== null,
37	  });
38	}
39	
40	function invalidateMarketDependentQueries(qc: QueryClient, marketId: string) {
41	  void qc.invalidateQueries({ queryKey: queryKeys.marketEvents(marketId) });
42	  void qc.invalidateQueries({ queryKey: queryKeys.engineStats(marketId) });
43	  void invalidateMarketCollectionQueries(qc);
44	}
45	
46	function invalidateAccountExposureQuery(qc: QueryClient, accountId: string) {
47	  return qc.invalidateQueries({
48	    queryKey: queryKeys.accountExposure(accountId),
49	    exact: true,
50	  });
51	}
52	
53	function invalidateAccountExposureQueries(qc: QueryClient) {
54	  return qc.invalidateQueries({
55	    predicate: ({ queryKey }) => Array.isArray(queryKey)
56	      && queryKey.length === 3
57	      && queryKey[0] === "accounts"
58	      && typeof queryKey[1] === "string"
59	      && queryKey[2] === "exposure",
60	  });
61	}
62	
63	function refetchMarketRouteQueries(qc: QueryClient, marketId: string) {
64	  void qc.invalidateQueries({ queryKey: queryKeys.market(marketId) });
65	  invalidateMarketDependentQueries(qc, marketId);
66	}
67	
68	function isMarketStatus(value: unknown): value is MarketStatus {
69	  return value === "active" || value === "resolved" || value === "closed" || value === "draft";
70	}
71	
72	function isRecord(value: unknown): value is Record<string, unknown> {
73	  return typeof value === "object" && value !== null;
74	}
75	
76	function parseMarginals(value: unknown): Record<string, number> | null {
77	  if (!isRecord(value)) {
78	    return null;
79	  }
80	
81	  const marginals: Record<string, number> = {};
82	  for (const [outcomeId, probability] of Object.entries(value)) {
83	    if (typeof probability !== "number" || !Number.isFinite(probability)) {
84	      return null;
85	    }
86	    marginals[outcomeId] = probability;
87	  }
88	  return marginals;
89	}
90	
91	function parseMarketPriceMessage(value: unknown): MarketPriceMessage | null {
92	  if (!isRecord(value)) {
93	    return null;
94	  }
95	
96	  if (
97	    typeof value.marketId !== "string"
98	    || !isMarketStatus(value.status)
99	    || typeof value.seq !== "number"
100	    || !Number.isFinite(value.seq)
101	    || typeof value.emittedAt !== "string"
102	    || typeof value.approxFlag !== "boolean"
103	  ) {
104	    return null;
105	  }
106	
107	  const marginals = parseMarginals(value.marginals);
108	  if (!marginals) {
109	    return null;
110	  }
111	
112	  let resolutionProbabilities: Record<string, number> | undefined;
113	  if (value.resolutionProbabilities != null) {
114	    const parsedResolutionProbabilities = parseMarginals(value.resolutionProbabilities);
115	    if (!parsedResolutionProbabilities) {
116	      return null;
117	    }
118	    resolutionProbabilities = parsedResolutionProbabilities;
119	  }
120	
121	  return {
122	    marketId: value.marketId,
123	    status: value.status,
124	    marginals,
125	    seq: value.seq,
126	    emittedAt: value.emittedAt,
127	    approxFlag: value.approxFlag,
128	    resolution: typeof value.resolution === "string" ? value.resolution : undefined,
129	    resolutionProbabilities,
130	  };
131	}
132	
133	export function useMarketPriceSubscription(marketId: string, opts?: { enabled?: boolean }) {
134	  const qc = useQueryClient();
135	  const enabled = opts?.enabled ?? true;
136	  const lastSeqRef = useRef<number>(-1);
137	  const reconnectAttemptRef = useRef(0);
138	  const reconnectTimerRef = useRef<number | null>(null);
139	
140	  useEffect(() => {
141	    if (!enabled || marketId.length === 0) {
142	      lastSeqRef.current = -1;
143	      reconnectAttemptRef.current = 0;
144	      if (reconnectTimerRef.current != null) {
145	        window.clearTimeout(reconnectTimerRef.current);
146	        reconnectTimerRef.current = null;
147	      }
148	      return;
149	    }
150	
151	    lastSeqRef.current = -1;
152	    reconnectAttemptRef.current = 0;
153	
154	    let socket: WebSocket | null = null;
155	    let effectClosed = false;
156	    let terminalStatus: MarketStatus | null = null;
157	
158	    const clearReconnectTimer = () => {
159	      if (reconnectTimerRef.current != null) {
160	        window.clearTimeout(reconnectTimerRef.current);
161	        reconnectTimerRef.current = null;
162	      }
163	    };
164	
165	    const scheduleReconnect = () => {
166	      clearReconnectTimer();
167	      const attempt = reconnectAttemptRef.current;
168	      const delay = Math.min(
169	        MAX_RECONNECT_DELAY_MS,
170	        INITIAL_RECONNECT_DELAY_MS * (2 ** attempt),
171	      );
172	      reconnectAttemptRef.current += 1;
173	      reconnectTimerRef.current = window.setTimeout(() => {
174	        if (effectClosed || terminalStatus !== null) {
175	          return;
176	        }
177	        refetchMarketRouteQueries(qc, marketId);
178	        connect();
179	      }, delay);
180	    };
181	
182	    const connect = () => {
183	      if (effectClosed || terminalStatus !== null) {
184	        return;
185	      }
186	
187	      socket = new WebSocket(api.getMarketPricesWebSocketUrl(marketId));
188	
189	      socket.addEventListener("open", () => {
190	        const reconnecting = reconnectAttemptRef.current > 0;
191	        reconnectAttemptRef.current = 0;
192	        clearReconnectTimer();
193	        if (reconnecting) {
194	          refetchMarketRouteQueries(qc, marketId);
195	        }
196	      });
197	
198	      socket.addEventListener("message", (event) => {
199	        if (typeof event.data !== "string") {
200	          return;
201	        }
202	
203	        let raw: unknown;
204	        try {
205	          raw = JSON.parse(event.data);
206	        } catch {
207	          return;
208	        }
209	
210	        const update = parseMarketPriceMessage(raw);
211	        if (!update || update.marketId !== marketId || update.seq <= lastSeqRef.current) {
212	          return;
213	        }
214	
215	        lastSeqRef.current = update.seq;
216	        qc.setQueryData<MarketDetailResponse>(queryKeys.market(marketId), (current) => {
217	          if (!current) {
218	            return current;
219	          }
220	
221	          return {
222	            ...current,
223	            market: {
224	              ...current.market,
225	              status: update.status,
226	              marginals: update.marginals,
227	              resolution: update.resolution ?? current.market.resolution,
228	              resolutionProbabilities: update.resolutionProbabilities ?? current.market.resolutionProbabilities,
229	            },
230	          };
231	        });
232	
233	        invalidateMarketDependentQueries(qc, marketId);
234	
235	        if (update.status !== "active") {
236	          terminalStatus = update.status;
237	          refetchMarketRouteQueries(qc, marketId);
238	          socket?.close();
239	        }
240	      });
241	
242	      socket.addEventListener("error", () => {
243	        socket?.close();
244	      });
245	
246	      socket.addEventListener("close", () => {
247	        socket = null;
248	        if (effectClosed) {
249	          return;
250	        }
251	
252	        if (terminalStatus !== null) {
253	          return;
254	        }
255	
256	        refetchMarketRouteQueries(qc, marketId);
257	        scheduleReconnect();
258	      });
259	    };
260	
261	    connect();
262	
263	    return () => {
264	      effectClosed = true;
265	      clearReconnectTimer();
266	      reconnectAttemptRef.current = 0;
267	      terminalStatus = null;
268	      socket?.close();
269	      socket = null;
270	    };
271	  }, [enabled, marketId, qc]);
272	}
273	
274	export function useMarkets(filters?: MarketListFilterInput) {
275	  return useQuery({
276	    queryKey: queryKeys.markets(filters),
277	    queryFn: () => api.listMarkets(filters),
278	    refetchInterval: 5000,
279	  });
280	}
281	
