306	  return useQuery({
307	    queryKey: queryKeys.engineStats(marketId),
308	    queryFn: () => api.getEngineStats(marketId),
309	    enabled: opts?.enabled ?? true,
310	  });
311	}
312	
313	export function useMarketAnalytics(marketId: string, opts?: { interval?: string; enabled?: boolean }) {
314	  const interval = opts?.interval;
315	  return useQuery({
316	    queryKey: queryKeys.marketAnalytics(marketId, interval),
317	    queryFn: () => api.getMarketAnalytics(marketId, interval),
318	    enabled: opts?.enabled ?? true,
